function solve(nums: number[]): number {
    // 1. Identify unique values S and store them in a Set for O(1) lookup
    const uniqueValuesSet = new Set<number>();
    let V_MAX = 0;
    for (const x of nums) {
        uniqueValuesSet.add(x);
        if (x > V_MAX) {
            V_MAX = x;
        }
    }

    // Convert to sorted array S_sorted
    const S_sorted = Array.from(uniqueValuesSet).sort((a, b) => a - b);

    // 2. Initialize Map M: M[s] stores the minimum achievable value for s
    const M = new Map<number, number>();
    for (const s of S_sorted) {
        M.set(s, s);
    }

    // 3 & 4. Iterate through divisors d in S_sorted in increasing order
    // Since we iterate in increasing order, M[d] will hold its minimal value 
    // before it's used to update its multiples.
    for (const d of S_sorted) {
        const Md = M.get(d)!;

        // 5. Iterate over multiples m = k * d (k > 1) present in S
        for (let m = 2 * d; m <= V_MAX; m += d) {
            // Check if m is present in the original set S
            if (uniqueValuesSet.has(m)) {
                const Mm_current = M.get(m)!;
                // Update M[m] if M[d] provides a smaller replacement value
                if (Md < Mm_current) {
                    M.set(m, Md);
                }
            }
        }
    }

    // 6. Calculate the final sum
    let totalSum = 0;
    for (const x of nums) {
        // M[x] holds the smallest achievable value for the original element x
        totalSum += M.get(x)!;
    }

    return totalSum;
}
