function solve(nums: number[]): number {
    const MAX_VAL_CONSTRAINT = 100000;

    // 1. Determine the necessary limit and identify the set S
    let maxN = 0;
    for (const num of nums) {
        if (num > maxN) {
            maxN = num;
        }
    }
    const limit = Math.min(maxN, MAX_VAL_CONSTRAINT);

    // inS[i] is true if i is present in nums (i.e., i in S)
    const inS = new Array(limit + 1).fill(false);
    for (const num of nums) {
        inS[num] = true;
    }

    // M_val[x] stores the minimum value y in S such that y divides x (m(x)).
    // Initialize M_val[x] = x for x in S.
    const M_val = new Array(limit + 1).fill(0);
    for (let i = 1; i <= limit; i++) {
        if (inS[i]) {
            M_val[i] = i;
        }
    }

    // 2. Sieve process: Find the smallest divisor y in S for every x in S
    // Iterate y from 1 up to limit
    for (let y = 1; y <= limit; y++) {
        if (!inS[y]) {
            continue; // y must be present in nums (y in S) to be used as a divisor
        }

        // y is a divisor candidate in S

        // Iterate over multiples x of y, up to limit
        for (let x = y; x <= limit; x += y) {
            if (inS[x]) {
                // x is in S and y divides x.

                // Since we process y in increasing order, if y is a divisor of x in S,
                // and M_val[x] is still greater than y, then y must be the new minimum divisor.
                if (y < M_val[x]) {
                     M_val[x] = y;
                }
            }
        }
    }

    // 3. Calculate the total minimum sum
    let totalSum = 0;
    for (const num of nums) {
        totalSum += M_val[num];
    }

    return totalSum;
}

