function solve(nums: number[]): number {
    // 1. Find the set of unique elements U
    const uniqueNums = new Set<number>(nums);

    let totalMinSum = 0;

    // 2. Iterate through each element N_i in the original nums array
    for (const Ni of nums) {
        let D_star = Ni; // Initialize D_star to Ni, as Ni always divides itself and is in U

        // Find divisors of Ni and check which ones are in U, finding the minimum
        // We only need to check up to sqrt(Ni)
        const limit = Math.floor(Math.sqrt(Ni));

        for (let d = 1; d <= limit; d++) {
            if (Ni % d === 0) {
                // Check divisor d
                if (uniqueNums.has(d)) {
                    D_star = Math.min(D_star, d);
                }

                // Check conjugate divisor Ni/d
                const d_conj = Ni / d;
                if (uniqueNums.has(d_conj)) {
                    D_star = Math.min(D_star, d_conj);
                }
            }
        }

        // 3. Add the minimum reachable value D_star to the total sum
        totalMinSum += D_star;
    }

    return totalMinSum;
}

